"use client";

import { useMemo, useState } from "react";
import { Bot, Send, Sparkles, X } from "lucide-react";

type GuidanceResponse = {
  disease: string;
  prescription: string;
  llmGuidance: {
    summary: string;
    domesticRemedies: string[];
    precautions: string[];
    whenToSeekDoctor: string;
  };
  disclaimer: string;
};

type ChatMessage = {
  id: string;
  role: "bot" | "user";
  text: string;
};

export default function PatientChatbot() {
  const [open, setOpen] = useState(false);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: "welcome",
      role: "bot",
      text: "Hi! I am your health assistant. Please type your disease name, and I will suggest domestic remedies using AI guidance.",
    },
  ]);

  const canSend = useMemo(() => input.trim().length > 0 && !loading, [
    input,
    loading,
  ]);

  const pushBotMessage = (text: string) => {
    setMessages((prev) => [
      ...prev,
      {
        id: `${Date.now()}-bot`,
        role: "bot",
        text,
      },
    ]);
  };

  const handleSend = async () => {
    const disease = input.trim();
    if (!disease || loading) return;

    const user = JSON.parse(localStorage.getItem("user") || "{}");

    if (!user?.patientId) {
      pushBotMessage("I could not find your patient profile. Please login again.");
      return;
    }

    setMessages((prev) => [
      ...prev,
      {
        id: `${Date.now()}-user`,
        role: "user",
        text: disease,
      },
    ]);

    setInput("");
    setLoading(true);

    try {
      const response = await fetch(
        `http://localhost:5000/api/patient/${user.patientId}/chatbot/guidance`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
          body: JSON.stringify({ disease }),
        }
      );

      const data = (await response.json()) as GuidanceResponse | { message?: string };

      if (!response.ok) {
        throw new Error(
          (data as { message?: string })?.message ||
            "Failed to get guidance from assistant"
        );
      }

      const payload = data as GuidanceResponse;

      const reply = [
        `Disease: ${payload.disease}`,
        "",
        `Prescription from your records: ${payload.prescription}`,
        "",
        `AI summary: ${payload.llmGuidance.summary}`,
        "",
        "Domestic remedies:",
        ...payload.llmGuidance.domesticRemedies.map((item) => `- ${item}`),
        "",
        "Precautions:",
        ...payload.llmGuidance.precautions.map((item) => `- ${item}`),
        "",
        `When to seek doctor: ${payload.llmGuidance.whenToSeekDoctor}`,
        "",
        payload.disclaimer,
      ].join("\n");

      pushBotMessage(reply);
    } catch (error: any) {
      pushBotMessage(
        error?.message ||
          "Something went wrong while contacting the AI assistant."
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <button
        type="button"
        onClick={() => setOpen((prev) => !prev)}
        className="fixed bottom-6 right-6 z-50 h-14 w-14 rounded-full bg-emerald-500 text-slate-900 shadow-xl hover:bg-emerald-400 transition flex items-center justify-center"
        aria-label="Open patient chatbot"
      >
        {open ? <X className="h-6 w-6" /> : <Bot className="h-6 w-6" />}
      </button>

      {open && (
        <div className="fixed bottom-24 right-6 z-50 w-[92vw] max-w-sm rounded-2xl border border-white/15 bg-slate-900/95 backdrop-blur-xl shadow-2xl">
          <div className="flex items-center gap-2 px-4 py-3 border-b border-white/10">
            <Sparkles className="h-4 w-4 text-emerald-300" />
            <p className="text-sm font-semibold text-white">Patient Health Assistant</p>
          </div>

          <div className="h-80 overflow-y-auto px-3 py-3 space-y-2">
            {messages.map((message) => (
              <div
                key={message.id}
                className={`rounded-xl px-3 py-2 text-sm whitespace-pre-wrap ${
                  message.role === "user"
                    ? "ml-10 bg-emerald-500 text-slate-900"
                    : "mr-6 bg-white/10 text-slate-100"
                }`}
              >
                {message.text}
              </div>
            ))}

            {loading && (
              <div className="mr-6 rounded-xl px-3 py-2 text-sm bg-white/10 text-slate-100">
                Thinking...
              </div>
            )}
          </div>

          <div className="flex items-center gap-2 px-3 py-3 border-t border-white/10">
            <input
              type="text"
              value={input}
              onChange={(event) => setInput(event.target.value)}
              onKeyDown={(event) => {
                if (event.key === "Enter") {
                  event.preventDefault();
                  handleSend();
                }
              }}
              placeholder="Enter disease name"
              className="flex-1 rounded-xl bg-slate-800 border border-slate-700 px-3 py-2 text-sm text-white placeholder:text-gray-500 outline-none focus:border-emerald-400"
            />
            <button
              type="button"
              onClick={handleSend}
              disabled={!canSend}
              className="h-10 w-10 rounded-xl bg-emerald-500 text-slate-900 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center"
              aria-label="Send disease message"
            >
              <Send className="h-4 w-4" />
            </button>
          </div>
        </div>
      )}
    </>
  );
}
